import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Industries = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // Category 'industries' ke liye data fetch karna
  useEffect(() => {
    const fetchIndustryPosts = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/blog/industries');
        setPosts(res.data);
      } catch (err) {
        console.error("Industries posts fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchIndustryPosts();
  }, []);

  return (
    <div className="bg-white antialiased w-full">

      {/* 1. FULL WIDTH HEADER */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-r from-[#1a1c1e] to-[#2c3136] text-white">
        <div className="w-full">
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter mb-6">
            Industries <span className="text-orange-400">Solutions</span>
          </h1>
          <p className="text-orange-100 text-lg md:text-xl font-light max-w-3xl leading-relaxed">
            Tailored manpower solutions for manufacturing, logistics, oil & gas, and infrastructure developments across the globe.
          </p>
        </div>
      </section>

      {/* 2. DYNAMIC SPOTLIGHT SECTION */}
      <section className="w-full bg-white border-t border-gray-100">
        <div className="py-16 px-6 md:px-16 w-full bg-gray-50 flex justify-between items-center">
          <div>
            <h2 className="text-5xl font-black text-gray-900 tracking-tighter">
              Sector <span className="text-orange-600">Spotlight</span>
            </h2>
            <div className="h-1.5 w-24 bg-orange-500 mt-4 rounded-full"></div>
          </div>
          <div className="hidden md:block">
            <span className="px-6 py-2 bg-white rounded-full border border-gray-200 text-xs font-black text-gray-400 uppercase tracking-[0.2em]">
              Hudson Global Network
            </span>
          </div>
        </div>

        <div className="w-full flex flex-col">
          {loading ? (
            <div className="py-40 text-center">
              <div className="inline-block w-10 h-10 border-4 border-orange-600 border-t-transparent rounded-full animate-spin mb-4"></div>
              <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">Loading Sector Insights...</p>
            </div>
          ) : posts.length > 0 ? (
            posts.map((post, index) => (
              <div 
                key={post._id || index} 
                className="w-full px-6 md:px-16 py-16 flex flex-col md:flex-row items-center gap-12 border-b border-gray-100 last:border-b-0 hover:bg-gray-50 transition-all group"
              >
                {/* Left Side: Media Box */}
                <div className="flex-shrink-0">
                  <div className="h-44 w-44 bg-white border-2 border-orange-100 rounded-[2.5rem] flex items-center justify-center text-7xl shadow-2xl overflow-hidden relative group">
                    {post.image ? (
                      <img src={post.image} alt={post.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                    ) : (
                      <span className="text-orange-500 group-hover:rotate-6 transition-transform">🏭</span>
                    )}
                    <div className="absolute inset-0 bg-gradient-to-tr from-orange-600/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                  </div>
                </div>

                {/* Right Side: Content */}
                <div className="flex-grow">
                  <div className="flex items-center gap-3 mb-4">
                    <span className="text-orange-600 font-black text-[10px] uppercase tracking-widest border-b-2 border-orange-600">
                      Market Intelligence
                    </span>
                    <span className="text-gray-400 font-bold text-[10px]">/</span>
                    <span className="text-gray-400 font-bold text-[10px] uppercase tracking-widest">
                      {post.date || 'Update 2026'}
                    </span>
                  </div>
                  <h3 className="text-3xl md:text-4xl font-black text-gray-950 mb-4 tracking-tighter group-hover:text-orange-600 transition-colors">
                    {post.title}
                  </h3>
                  <div className="relative">
                    <p className="text-gray-600 text-xl leading-relaxed italic max-w-5xl">
                      "{post.description}"
                    </p>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="py-32 text-center text-gray-300 italic text-xl">
              No industrial insights posted for this sector yet.
            </div>
          )}
        </div>
      </section>

      {/* 3. FULL WIDTH CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="w-full bg-gradient-to-r from-[#111] to-[#333] rounded-[4rem] p-12 md:p-20 flex flex-col md:flex-row items-center justify-between text-white shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-96 h-96 bg-orange-600/10 rounded-full blur-[120px]"></div>

          <div className="md:w-2/3 relative z-10">
            <h2 className="text-4xl md:text-6xl font-black mb-6 tracking-tighter leading-tight">
              Power Your Project <br /> <span className="text-orange-500 italic">With Professionals.</span>
            </h2>
            <p className="text-gray-400 text-xl mb-10 max-w-xl font-medium leading-relaxed">
              From on-site technicians to project managers, Hudson provides the backbone for global industries.
            </p>
            <Link to="/careers">
              <button className="bg-orange-600 text-white px-12 py-6 rounded-2xl font-black text-xl hover:bg-white hover:text-gray-950 transition-all shadow-xl active:scale-95">
                Join Our Talent Pool
              </button>
            </Link>
          </div>

          <div className="hidden md:flex md:w-1/3 justify-end relative z-10">
            <div className="h-64 w-64 border-4 border-white/5 rounded-full flex items-center justify-center">
               <span className="text-8xl opacity-10 filter grayscale">🏢</span>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Industries;
